// ============================================
// BID OUTCOME CHECKER - Feedback Loop
// ============================================
// For each bid change made >4h ago:
// 1. Check if the expected outcome happened
// 2. Mark as success/failure/neutral
// 3. Update escalation_failures on teasers
// 4. Adaptive: adjust future aggressiveness based on success rate

const expectations = $('Fetch Unchecked Expectations').all().map(i => i.json);
const statsItems = $('Fetch Current Stats').all().map(i => i.json);
const crmItems = $('Fetch Recent CRM Leads').all().map(i => i.json);

if (expectations.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No unchecked expectations' } }];
}

// Stats map
const statsMap = {};
statsItems.forEach(s => {
  statsMap[Number(s.ad_id)] = {
    spend: Number(s.total_spend) || 0,
    clicks: Number(s.total_clicks) || 0,
    cpc: Number(s.current_cpc) || 0,
    ctr: Number(s.current_ctr) || 0
  };
});

// CRM map
const crmMap = {};
crmItems.forEach(c => {
  crmMap[Number(c.ad_id)] = Number(c.total_leads) || 0;
});

const results = [];
let successCount = 0;
let failureCount = 0;
let neutralCount = 0;

expectations.forEach(exp => {
  const adId = Number(exp.ad_id);
  const stats = statsMap[adId];
  const leads = crmMap[adId] || 0;
  const baseline = Number(exp.baseline_value) || 0;

  let outcome = 'insufficient_data';
  let actualValue = null;

  if (!stats) {
    outcome = 'insufficient_data';
  } else {
    // Determine actual metric value
    switch (exp.expected_metric) {
      case 'cpl':
        actualValue = leads > 0 ? stats.spend / leads : (stats.spend > 0 ? 99999 : null);
        if (actualValue === null) {
          outcome = 'insufficient_data';
        } else if (exp.expected_direction === 'down') {
          outcome = actualValue < baseline * 0.9 ? 'success' : (actualValue > baseline * 1.1 ? 'failure' : 'neutral');
        } else {
          outcome = actualValue > baseline * 1.1 ? 'success' : (actualValue < baseline * 0.9 ? 'failure' : 'neutral');
        }
        break;
      case 'ctr':
        actualValue = stats.ctr;
        if (exp.expected_direction === 'up') {
          outcome = actualValue > baseline * 1.1 ? 'success' : (actualValue < baseline * 0.8 ? 'failure' : 'neutral');
        } else {
          outcome = actualValue < baseline * 0.9 ? 'success' : (actualValue > baseline * 1.2 ? 'failure' : 'neutral');
        }
        break;
      case 'cpc':
        actualValue = stats.cpc;
        if (exp.expected_direction === 'down') {
          outcome = actualValue < baseline * 0.85 ? 'success' : (actualValue > baseline * 1.05 ? 'failure' : 'neutral');
        }
        break;
      default:
        outcome = 'insufficient_data';
    }
  }

  if (outcome === 'success') successCount++;
  else if (outcome === 'failure') failureCount++;
  else neutralCount++;

  results.push({
    json: {
      expectation_id: exp.id,
      ad_id: adId,
      action: exp.action,
      expected_metric: exp.expected_metric,
      expected_direction: exp.expected_direction,
      baseline_value: baseline,
      actual_value: actualValue !== null ? Math.round(actualValue * 100) / 100 : null,
      outcome: outcome,
      old_bid: exp.old_bid,
      new_bid: exp.new_bid
    }
  });
});

// Add summary as first item
results.unshift({
  json: {
    is_summary: true,
    total_checked: expectations.length,
    success: successCount,
    failure: failureCount,
    neutral: neutralCount,
    insufficient_data: expectations.length - successCount - failureCount - neutralCount,
    success_rate: expectations.length > 0 ? Math.round((successCount / expectations.length) * 100) : 0
  }
});

return results;

// Format summary from the first item
const items = $input.all();
const summary = items.find(i => i.json.is_summary);

if (!summary) return [];

const s = summary.json;
const failures = items.filter(i => i.json.outcome === 'failure').slice(0, 5);

let msg = `BID OUTCOME CHECKER ${$now.toFormat('dd.MM.yyyy HH:mm')}\n`;
msg += `Checked: ${s.total_checked} | OK: ${s.success} | Fail: ${s.failure} | Neutral: ${s.neutral} | No data: ${s.insufficient_data}\n`;
msg += `Success rate: ${s.success_rate}%\n`;

if (failures.length > 0) {
  msg += `\nFailed changes:\n`;
  failures.forEach(f => {
    msg += `  #${f.json.ad_id}: ${f.json.action} ${f.json.expected_metric} expected ${f.json.expected_direction}, baseline ${f.json.baseline_value} -> actual ${f.json.actual_value}\n`;
  });
}

if (s.success_rate < 40 && s.total_checked >= 5) {
  msg += `\n⚠️ Low success rate! Consider reducing bid change aggressiveness.`;
}

return [{ json: { message: msg, success_rate: s.success_rate } }];
